schemas["nrob-v1"] = {"$comment":"This file is autogenerated, do not edit manually, see https://github.com/SAP/abap-file-formats for more information.","$schema":"https://json-schema.org/draft/2020-12/schema","$id":"https://github.com/SAP/abap-file-formats/blob/main/file-formats/nrob/nrob-v1.json","title":"NROB Object Type","description":"Object type NROB","type":"object","properties":{"formatVersion":{"title":"ABAP File Format Version","description":"The ABAP file format version","type":"string","const":"1"},"header":{"title":"Header","description":"Header","type":"object","properties":{"description":{"title":"Description","description":"Description of the ABAP object","type":"string","maxLength":60},"originalLanguage":{"title":"Original Language","description":"Original language of the ABAP object","type":"string","minLength":2},"abapLanguageVersion":{"title":"ABAP Language Version","description":"ABAP language version","type":"string","enum":["standard","cloudDevelopment"],"enumTitles":["Standard","ABAP Cloud Development"],"enumDescriptions":["Standard","ABAP cloud development"],"default":"standard"}},"additionalProperties":false,"required":["description","originalLanguage"]},"interval":{"title":"Interval","description":"Interval","type":"object","properties":{"numberLengthDomain":{"title":"Number Length Domain","description":"Name of domain, which determines the length of the number range number. Define the amount of characters available for number range intervals. It must be of type NUMC or CHAR and have a field length of at least 1 and at most 20.","type":"string","maxLength":30},"percentWarning":{"title":"Percent Warning","description":"Percentage of numbers remaining in a number range, upon reaching which in number assignment a warning is given. It must be between 0.1 and 99.9. Example: You have defined an interval from 1 to 1000. If you want to issue a warning at the number 900, enter 10 (%) here.","type":"number","minimum":0.1,"maximum":99.9},"subType":{"title":"Sub Type","description":"If you want to create subobjects for the elements of a field of the application table, specify the relevant data element for this table field. This data element must be active in the Data Dictionary and must have a check table. The domain of the data element must have a field length of between 1 and 6.","type":"string","maxLength":30},"untilYear":{"title":"Until Year","description":"If you want the records of the business object to be differentiated by financial year, you set this option true. This structures the intervals of a number range object.","type":"boolean"},"rolling":{"title":"Rolling","description":"For each interval of a number range object, the system checks when the available characters are used up. In the true setting, once the available characters of an interval are used up, the system starts again from the beginning and the lowest number is assigned again. You can suppress this behavior by setting this option false. If you do this, no more characters from an interval are assigned once the characters of the interval are used up. You can suppress rollover for the entire number range object, that is, the setting applies to all the intervals contained in the object.","type":"boolean"},"prefix":{"title":"Prefix","description":"If it is set to true determined numbers consist of the prefix (name of subobject) and the numbers.","type":"boolean"}},"additionalProperties":false,"required":["numberLengthDomain","percentWarning","subType","untilYear","rolling","prefix"]},"configuration":{"title":"Configuration","description":"Configuration-specific fields","type":"object","properties":{"transactionId":{"title":"Transaction ID","description":"Transaction code for application specific transaction","type":"string","maxLength":20},"buffering":{"title":"Buffering","description":"Choose a buffer type for no buffering, for buffering via main memory or for parallel buffering. Default is mainBuffer.","type":"string","enum":["mainBuffer","parallel","none"],"enumTitles":["Main Memory Buffering","Parallel Buffering","No Buffering"],"enumDescriptions":["Main memory buffering is the most efficient buffering solution with regards to system performance. Almost all number range objects use main memory buffering. However, it does have two restrictions: Numbers can no longer be assigned in chronological order. The numbering may contain gaps.","Parallel buffering works in the same way as main memory buffering, with the difference that the number packages are not stored in the main memory, but are written to the table NRIVSHADOW.","No buffering method is used. A number is taken from an interval stored in database NRIV. The table line is locked and this lock remains until the application that requested the number is closed, either with a COMMIT WORK or a ROLLBACK."],"default":"mainBuffer"},"bufferedNumbers":{"title":"Buffered Numbers","description":"This value specifies the numbers in buffer. In case of parallel and main memory buffering, add a number for 'bufferedNumbers'. It determines how many numbers are reserved in buffer for the intervals.Default number of buffers is 10.","type":"integer","minimum":0,"maximum":99999999,"default":10}},"additionalProperties":false,"required":["buffering","bufferedNumbers"]}},"additionalProperties":false,"required":["formatVersion","header","interval","configuration"]};
